INSERT INTO `respuestas_predefinidas` VALUES (1,'Solicitud Recibida','General','Su solicitud ha sido recibida exitosamente. Un administrador revisara su caso y le dara seguimiento en los proximos dias habiles.','solicitud,recibida,confirmacion',1,1,7,'2026-06-07 20:30:43'),(2,'Documentacion Incompleta','Documentos','Hemos revisado su solicitud y hemos detectado que la documentacion esta incompleta. Por favor revise los requisitos y vuelva a subir los documentos faltantes.','documentos,incompleta,requisitos',1,1,7,'2026-06-07 20:30:43'),(3,'Beca Aprobada','Becas','Felicitaciones! Su solicitud de beca ha sido aprobada. El beneficio sera aplicado a partir del siguiente periodo academico.','beca,aprobada,beneficio',1,1,7,'2026-06-07 20:30:43'),(4,'Beca Rechazada','Becas','Lamentamos informarle que su solicitud de beca no ha sido aprobada. Puede solicitar una revision o volver a aplicar en el proximo periodo.','beca,rechazada,revision',1,1,7,'2026-06-07 20:30:43'),(5,'Cita Programada','Citas','Se ha programado su cita con el departamento de bienestar. Por favor confirme su asistencia y llegue puntual a la hora indicada.','cita,programada,confirmacion',1,1,7,'2026-06-07 20:30:43'),(6,'Ficha Aprobada','Fichas','Su ficha socioeconomica ha sido revisada y aprobada. Ya puede proceder con la solicitud de becas disponibles.','ficha,aprobada,socioeconomica',1,1,7,'2026-06-07 20:30:43'),(7,'Informacion General','General','Gracias por contactarnos. Para brindarle una mejor atencion, por favor especifique el detalle de su consulta.','informacion,consulta,general',1,1,7,'2026-06-07 20:30:43'),(8,'Solicitud en Proceso','General','Su solicitud esta siendo procesada. Le notificaremos cuando haya una actualizacion en el estado de su tramite.','solicitud,proceso,pendiente',1,1,7,'2026-06-07 20:30:43');
/*!40000 ALTER TABLE `respuestas_predefinidas` ENABLE KEYS */;
