INSERT INTO `solicitudes_ayuda` VALUES (100,104,'Problema con inscripcion a becas',36,'No puedo acceder al formulario de becas','Estimados, desde hace 3 dias intento acceder al formulario de solicitud de becas pero el sistema me muestra un error. Ya probe con varios navegadores.','Se resolvio el problema tecnico. Ya puede acceder al formulario.','2025-03-10 09:30:00','Resuelta','Alta','2026-06-07 20:33:03',7,'2026-06-08 01:33:03'),(101,105,'Consulta sobre requisitos de ficha',37,'Documentacion para ficha socioeconomica','Buenos dias, quisiera saber que documentos necesito presentar para completar mi ficha socioeconomica.','Los requisitos estan disponibles en la pagina principal del modulo de bienestar.','2025-03-15 10:00:00','Resuelta','Media','2026-06-07 20:33:03',100,'2026-06-08 01:33:03'),(102,150,'Problema de salud',38,'','Estoy pasando por una situacion de salud delicada y necesito apoyo del departamento de bienestar para justificar mis inasistencias.','','2025-04-20 14:00:00','En Proceso','Urgente','2026-06-07 20:33:03',7,'2026-06-08 01:33:03'),(103,200,'Problema de vivienda',39,'Necesito ayuda con alquiler','Actualmente estoy atravesando dificultades economicas y no puedo pagar el arriendo de este mes. Solicito orientacion sobre posibles ayudas.','','2025-05-01 11:00:00','Pendiente','Alta','2026-06-07 20:33:03',NULL,'2026-06-08 01:33:03'),(104,250,'Problemas de convivencia',40,'','Tengo conflictos con mis companeros de aula y esto esta afectando mi rendimiento academico. Solicito una mediacion.','Se programo una reunion de mediacion para el dia viernes.','2025-05-10 09:00:00','Resuelta','Media','2026-06-07 20:33:03',100,'2026-06-08 01:33:03'),(105,300,'Error en el sistema',41,'No puedo subir documentos','Cada vez que intento subir mis documentos la pagina se queda cargando y nunca termina.','El problema fue resuelto, era un error de configuracion del servidor.','2025-06-01 15:30:00','Resuelta','Alta','2026-06-07 20:33:03',7,'2026-06-08 01:33:03'),(106,350,'Consulta general',42,'Informacion sobre servicios','Me gustaria conocer todos los servicios que ofrece el departamento de bienestar estudiantil.','Se envio el folleto informativo por correo electronico.','2025-06-15 08:00:00','Resuelta','Baja','2026-06-07 20:33:03',101,'2026-06-08 01:33:03'),(107,400,'Problema economico',37,'Ayuda economica urgente','Soy estudiante de bajos recursos y necesito ayuda para comprar mis materiales de estudio.','','2025-07-01 10:00:00','Pendiente','Urgente','2026-06-07 20:33:03',NULL,'2026-06-08 01:33:03'),(108,450,'Dudas sobre becas',36,'Requisitos para beca deportiva','Quisiera saber cuales son los requisitos especificos para postular a la beca deportiva.','Los requisitos son: certificado deportivo, carta aval y record de notas.','2025-07-20 11:30:00','Resuelta','Media','2026-06-07 20:33:03',102,'2026-06-08 01:33:03'),(109,500,'Otro asunto',42,'Sugerencia para mejora','Propongo que implementen un chat en linea para consultas rapidas con el departamento de bienestar.','Gracias por su sugerencia, sera evaluada por el departamento de sistemas.','2025-08-05 16:00:00','Cerrada','Baja','2026-06-07 20:33:03',7,'2026-06-08 01:33:03'),(110,104,'Problema tecnico',41,'Error al cargar ficha','El sistema no guarda los cambios en mi ficha socioeconomica.','Ya se corrigio el error. Vuelva a intentarlo.','2025-08-20 09:00:00','Resuelta','Alta','2026-06-07 20:33:03',100,'2026-06-08 01:33:03'),(111,180,'Ayuda psicologica',38,'','Necesito atencion psicologica urgente por problemas personales.','','2025-09-01 08:30:00','Pendiente','Urgente','2026-06-07 20:33:03',NULL,'2026-06-08 01:33:03'),(112,220,'Problema con documentos',37,'Documentos perdidos','Subi mis documentos pero no aparecen en el sistema.','','2025-09-15 14:00:00','En Proceso','Alta','2026-06-07 20:33:03',7,'2026-06-08 01:33:03'),(113,280,'Dudas financieras',37,'Beca economica','Quisiera saber cuando se realizara el desembolso de la beca economica aprobada.','Los desembolsos se realizan la primera semana de cada mes.','2025-10-01 10:00:00','Resuelta','Media','2026-06-07 20:33:03',101,'2026-06-08 01:33:03'),(114,320,'Problema de horario',36,'','Mi horario de clases se cruza con las atenciones de bienestar. Hay horarios alternativos?','','2025-10-15 11:00:00','Pendiente','Baja','2026-06-07 20:33:03',NULL,'2026-06-08 01:33:03'),(115,360,'Seguimiento de beca',36,'Estado de mi solicitud','Ya paso un mes desde que solicite la beca y aun no tengo respuesta.','Su solicitud esta siendo evaluada. Le notificaremos pronto.','2025-11-01 09:00:00','En Proceso','Media','2026-06-07 20:33:03',100,'2026-06-08 01:33:03'),(116,400,'Problema de conexion',41,'','El internet del campus no funciona y necesito terminar mi solicitud en linea.','','2025-11-15 08:00:00','Cerrada','Alta','2026-06-07 20:33:03',7,'2026-06-08 01:33:03'),(117,450,'Ayuda con tramites',36,'','No entiendo como llenar el formulario de solicitud de beca. Me podrian ayudar?','Se le brindo asistencia personalizada en la oficina de bienestar.','2025-12-01 10:30:00','Resuelta','Media','2026-06-07 20:33:03',102,'2026-06-08 01:33:03'),(118,500,'Problema personal',38,'','Estoy pasando por una situacion familiar dificil y necesito apoyo.','Se le asigno un acompanamiento psicologico.','2026-01-15 14:00:00','Resuelta','Alta','2026-06-07 20:33:03',7,'2026-06-08 01:33:03'),(119,130,'Informacion sobre talleres',42,'Talleres disponibles','Hay talleres de desarrollo profesional este semestre?','','2026-02-01 09:00:00','Pendiente','Baja','2026-06-07 20:33:03',NULL,'2026-06-08 01:33:03'),(125,40,'Dificultades de aprendizaje en programación',36,NULL,'Tengo problemas para comprender la lógica de los algoritmos y necesito tutorías.',NULL,'2026-07-08 10:00:00','Pendiente','Media','2026-07-10 07:22:44',7,'2026-07-10 12:22:44'),(126,40,'Problemas económicos de transporte',37,NULL,'Debido a la distancia del instituto, los costos de pasajes superan mi presupuesto actual.',NULL,'2026-07-07 09:30:00','En Proceso','Alta','2026-07-10 07:22:44',100,'2026-07-10 12:22:44'),(127,40,'Chequeo médico preventivo general',38,NULL,'Solicito atención para un chequeo de rutina por molestias menores.','Se ha programado su cita para el día de mañana a las 8:00 AM en el consultorio médico.','2026-07-05 08:00:00','Resuelta','Baja','2026-07-10 07:22:44',101,'2026-07-10 12:22:44'),(128,40,'Orientación psicológica por estrés',38,NULL,'Presento cuadros de ansiedad debido a la carga académica acumulada.','Se derivó al estudiante con el especialista y se completaron las 3 sesiones programadas.','2026-07-01 11:15:00','Cerrada','Urgente','2026-07-10 07:22:44',102,'2026-07-10 12:22:44');
